// Function to insert a word into the trie
function insert(word) {
  let node = root;
  for (let char of word) {
    if (!node.children[char]) {
      node.children[char] = { value: false, children: {} };
    }
    node = node.children[char];
  }
  if (node.value) {
    return false;
  }
  node.value = true;
  return true;
}

let root = { value: false, children: {} };
